import React, { useState, useEffect, useCallback, useRef } from 'react';
import {
  Button, Dialog, DialogActions, DialogContent, DialogTitle,
  FormControl, InputLabel, MenuItem, Select, TextField,
  Typography, Box,
} from '@mui/material';
import ZoomInIcon from '@mui/icons-material/ZoomIn';
import ZoomOutIcon from '@mui/icons-material/ZoomOut';
import CenterFocusStrongIcon from '@mui/icons-material/CenterFocusStrong';
import axios from 'axios';
import * as d3 from 'd3';

function AdamToMuhammad({ user }) {
  const svgHorizontalRef = useRef(null);
  const svgVerticalRef = useRef(null);
  const containerHorizontalRef = useRef(null);
  const containerVerticalRef = useRef(null);
  const zoomRef = useRef(null);

  const [chain, setChain] = useState([]);
  const [loading, setLoading] = useState(true);

  const emptyMember = {
    name: '', generation_number: '', info: '', parent_id: '',
    father_name: '', mother_name: '', wife_name: '', urdu_name: '',
    birth_year: '', death_year: '', is_alive: true, photo: null,
  };

  const [open, setOpen] = useState(false);
  const [editOpen, setEditOpen] = useState(false);
  const [editingNode, setEditingNode] = useState(null);
  const [editData, setEditData] = useState(emptyMember);
  const [newData, setNewData] = useState(emptyMember);
  const [addRelation, setAddRelation] = useState('child');

  const token = localStorage.getItem('token');
  const isAdmin = user && user.role === 'admin';

  const loadChain = useCallback(async () => {
    try {
      const res = await axios.get('/api/prophets');
      setChain(res.data);
    } catch (err) { console.error(err); } finally { setLoading(false); }
  }, []);

  useEffect(() => { loadChain(); }, [loadChain]);

  const getFatherName = useCallback((node) => {
    if (!node?.parent_id) return null;
    const father = chain.find(n => n.id === node.parent_id);
    return father ? father.name : null;
  }, [chain]);

  const horizontalChain = chain.filter(n => n.generation_number <= 78);
  const verticalChain = chain.filter(n => n.generation_number >= 78);

  const getParentDetails = useCallback((node) => {
    if (!node) return { father_name: '', mother_name: '' };
    const parent = chain.find(n => n.id === node.parent_id);
    return {
      father_name: parent ? parent.name : '',
      mother_name: parent ? parent.wife_name || '' : '',
    };
  }, [chain]);

  const handleAddChild = useCallback((node) => {
    setAddRelation('child');
    setNewData({
      ...emptyMember,
      generation_number: node.generation_number + 1,
      parent_id: node.id,
      father_name: node.name,
      mother_name: node.wife_name || '',
    });
    setOpen(true);
  }, []);

  const handleAddSibling = useCallback((node) => {
    setAddRelation('sibling');
    const { father_name, mother_name } = getParentDetails(node);
    setNewData({
      ...emptyMember,
      generation_number: node.generation_number,
      parent_id: node.parent_id || '',
      father_name,
      mother_name,
    });
    setOpen(true);
  }, [getParentDetails]);

  const handleAddSpouse = useCallback((node) => {
    setAddRelation('spouse');
    setNewData({
      ...emptyMember,
      generation_number: node.generation_number,
      parent_id: '',
      wife_name: node.name,
    });
    setOpen(true);
  }, []);

  const handleEdit = useCallback((node) => {
    setEditingNode(node);
    setEditData({
      ...emptyMember,
      name: node.name || '',
      generation_number: node.generation_number || '',
      info: node.info || '',
      parent_id: node.parent_id || '',
      father_name: node.father_name || '',
      mother_name: node.mother_name || '',
      wife_name: node.wife_name || '',
      urdu_name: node.urdu_name || '',
      birth_year: node.birth_year || '',
      death_year: node.death_year || '',
      is_alive: node.is_alive !== undefined ? node.is_alive : true,
      photo: null,
    });
    setEditOpen(true);
  }, []);

  const handleDelete = useCallback(async (node) => {
    if (!window.confirm(`Delete ${node.name}?`)) return;
    try {
      await axios.delete(`/api/prophets/${node.id}`, { headers: { 'x-auth-token': token } });
      loadChain();
    } catch (err) { alert(err.response?.data?.msg || 'Delete failed'); }
  }, [token, loadChain]);

  const handleAddSubmit = async () => { /* same as before */ };
  const handleEditSubmit = async () => { /* same as before */ };

  // ─── Horizontal drawing (unchanged) ───
  const drawHorizontal = useCallback(() => { /* ... same ... */ }, [horizontalChain, isAdmin, getFatherName, handleEdit]);

  // ─── Vertical tree with dynamic big box ───
  const drawVertical = useCallback(() => {
    const svg = d3.select(svgVerticalRef.current);
    svg.selectAll('*').remove();
    if (verticalChain.length === 0) return;

    // ✅ Dynamic box sizing helper
    const getBoxSize = (node) => {
      const wifeLen = node.wife_name ? node.wife_name.length : 0;
      const infoLen = node.info ? node.info.length : 0;
      if (wifeLen > 30 || infoLen > 50) {
        return { boxW: 340, boxH: 260 };
      }
      return { boxW: 280, boxH: 230 };
    };

    const defaultNodeW = 320, defaultNodeH = 260;
    const padding = 200;

    // Build hierarchy
    const idMap = {};
    verticalChain.forEach(n => { idMap[n.id] = { ...n, children: [] }; });
    const roots = [];
    verticalChain.forEach(n => {
      if (!n.parent_id || !idMap[n.parent_id]) {
        roots.push(idMap[n.id]);
      } else {
        idMap[n.parent_id].children.push(idMap[n.id]);
      }
    });

    let rootData = roots.length === 1 ? roots[0] : { name: 'Root', children: roots, generation_number: 0, id: -1 };

    const root = d3.hierarchy(rootData);
    const treeLayout = d3.tree().nodeSize([defaultNodeW, defaultNodeH]);
    treeLayout(root);

    const descendants = root.descendants().filter(d => d.data.id !== -1);
    const links = root.links().filter(l => l.source.data.id !== -1 && l.target.data.id !== -1);

    // Calculate bounds with actual box sizes
    let minX = Infinity, maxX = -Infinity, minY = Infinity, maxY = -Infinity;
    descendants.forEach(d => {
      const { boxW, boxH } = getBoxSize(d.data);
      const x = d.x, y = d.y;
      minX = Math.min(minX, x - boxW / 2);
      maxX = Math.max(maxX, x + boxW / 2);
      minY = Math.min(minY, y - boxH / 2);
      maxY = Math.max(maxY, y + boxH / 2);
    });

    const width = (maxX - minX) + padding * 2;
    const height = (maxY - minY) + padding * 2;

    svg.attr('width', width).attr('height', height)
      .attr('viewBox', `0 0 ${width} ${height}`);

    const defs = svg.append('defs');
    const gradient = defs.append('linearGradient')
      .attr('id', 'vertGradient')
      .attr('x1', '0%').attr('y1', '0%')
      .attr('x2', '0%').attr('y2', '100%');
    gradient.append('stop').attr('offset', '0%').attr('stop-color', '#2E7D32');
    gradient.append('stop').attr('offset', '50%').attr('stop-color', '#c9a84c');
    gradient.append('stop').attr('offset', '100%').attr('stop-color', '#2E7D32');

    const g = svg.append('g')
      .attr('transform', `translate(${padding - minX}, ${padding - minY})`);

    const zoomBeh = d3.zoom().scaleExtent([0.1, 12]).on('zoom', e => {
      g.attr('transform', `translate(${e.transform.x}, ${e.transform.y}) scale(${e.transform.k})`);
    });
    svg.call(zoomBeh);
    const init = d3.zoomIdentity.translate(width / 2 - (minX + maxX) / 2, height / 2 - (minY + maxY) / 2).scale(1);
    svg.call(zoomBeh.transform, init);
    zoomRef.current = zoomBeh;

    // Links
    g.selectAll('.link').data(links, d => d.target.data.id)
      .join('path')
      .attr('fill', 'none')
      .attr('stroke', 'url(#vertGradient)')
      .attr('stroke-width', 2.5)
      .attr('d', d => {
        const sourceBox = getBoxSize(d.source.data);
        const targetBox = getBoxSize(d.target.data);
        const sx = d.source.x, sy = d.source.y + sourceBox.boxH / 2;
        const tx = d.target.x, ty = d.target.y - targetBox.boxH / 2;
        const my = (sy + ty) / 2;
        return `M${sx},${sy} L${sx},${my} L${tx},${my} L${tx},${ty}`;
      });

    // Nodes
    const nodeGroup = g.selectAll('.node').data(descendants, d => d.data.id)
      .join('g')
      .attr('class', 'node')
      .attr('transform', d => {
        const { boxW, boxH } = getBoxSize(d.data);
        return `translate(${d.x - boxW / 2}, ${d.y - boxH / 2})`;
      });

    // Card & content
    nodeGroup.each(function(d) {
      const { boxW, boxH } = getBoxSize(d.data);
      const gNode = d3.select(this);

      gNode.append('rect')
        .attr('width', boxW).attr('height', boxH)
        .attr('rx', 12).attr('ry', 12)
        .attr('fill', '#ffffffcc')
        .attr('stroke', '#2E7D32').attr('stroke-width', 2.5);
      gNode.append('rect')
        .attr('width', boxW).attr('height', 6).attr('rx', 3)
        .attr('fill', '#2E7D32');

      const contentH = boxH - 60;
      gNode.append('foreignObject')
        .attr('width', boxW - 20).attr('height', contentH)
        .attr('x', 10).attr('y', 10)
        .append('xhtml:div')
        .style('width', '100%').style('height', '100%')
        .style('display', 'flex').style('flex-direction', 'column')
        .style('align-items', 'center').style('justify-content', 'center')
        .style('text-align', 'center').style('font-size', '13px')
        .html(d => {
          const father = getFatherName(d.data);
          const fatherLine = father ? `<br/><span style="font-size:10px;color:#1565C0;">بن ${father}</span>` : '';
          const wifeLine = d.data.wife_name ? `<br/><span style="font-size:10px;color:#C2185B;">💍 ${d.data.wife_name}</span>` : '';
          return `<b>${d.data.name}</b>${fatherLine}${wifeLine}<br/><span style="font-size:10px;color:#555;">پشت: ${d.data.generation_number}</span>${d.data.info ? `<br/><span style="font-size:10px;color:#777;">${d.data.info}</span>` : ''}`;
        });
    });

    // Icons & admin buttons
    if (isAdmin) {
      nodeGroup.each(function(d) {
        const { boxW, boxH } = getBoxSize(d.data);
        const gNode = d3.select(this);
        const btnY = boxH - 32;

        // Child
        gNode.append('g').attr('transform', `translate(18, ${btnY})`).attr('cursor', 'pointer')
          .on('click', (e) => { e.stopPropagation(); handleAddChild(d.data); })
          .append('rect').attr('width', 46).attr('height', 24).attr('rx', 12)
          .attr('fill', '#fff').attr('stroke', '#2E7D32').attr('stroke-width', 1.4);
        gNode.select('g:last-child').append('text')
          .attr('x', 23).attr('y', 17).attr('text-anchor', 'middle')
          .attr('font-size', '16px').attr('font-weight', 700).attr('fill', '#2E7D32').text('⬇️');

        // Sibling
        gNode.append('g').attr('transform', `translate(${boxW / 2 - 23}, ${btnY})`).attr('cursor', 'pointer')
          .on('click', (e) => { e.stopPropagation(); handleAddSibling(d.data); })
          .append('rect').attr('width', 46).attr('height', 24).attr('rx', 12)
          .attr('fill', '#fff').attr('stroke', '#1565C0').attr('stroke-width', 1.4);
        gNode.select('g:last-child').append('text')
          .attr('x', 23).attr('y', 17).attr('text-anchor', 'middle')
          .attr('font-size', '16px').attr('font-weight', 700).attr('fill', '#1565C0').text('↔️');

        // Spouse
        gNode.append('g').attr('transform', `translate(${boxW - 64}, ${btnY})`).attr('cursor', 'pointer')
          .on('click', (e) => { e.stopPropagation(); handleAddSpouse(d.data); })
          .append('rect').attr('width', 46).attr('height', 24).attr('rx', 12)
          .attr('fill', '#fff').attr('stroke', '#C2185B').attr('stroke-width', 1.4);
        gNode.select('g:last-child').append('text')
          .attr('x', 23).attr('y', 17).attr('text-anchor', 'middle')
          .attr('font-size', '16px').attr('font-weight', 700).attr('fill', '#C2185B').text('💍');

        // Edit
        gNode.append('g').attr('transform', `translate(${boxW - 120}, 6)`).attr('cursor', 'pointer')
          .on('click', (e) => { e.stopPropagation(); handleEdit(d.data); })
          .append('rect').attr('width', 26).attr('height', 18).attr('rx', 8)
          .attr('fill', '#fff').attr('stroke', '#1565C0').attr('stroke-width', 1.2);
        gNode.select('g:last-child').append('text')
          .attr('x', 13).attr('y', 14).attr('text-anchor', 'middle')
          .attr('font-size', '12px').attr('font-weight', 'bold').attr('fill', '#1565C0').text('✎');

        // Delete
        gNode.append('g').attr('transform', `translate(${boxW - 80}, 6)`).attr('cursor', 'pointer')
          .on('click', (e) => { e.stopPropagation(); handleDelete(d.data); })
          .append('rect').attr('width', 26).attr('height', 18).attr('rx', 8)
          .attr('fill', '#fff').attr('stroke', '#C2185B').attr('stroke-width', 1.2);
        gNode.select('g:last-child').append('text')
          .attr('x', 13).attr('y', 14).attr('text-anchor', 'middle')
          .attr('font-size', '12px').attr('font-weight', 'bold').attr('fill', '#C2185B').text('✕');
      });
    }
  }, [verticalChain, isAdmin, getFatherName, handleAddChild, handleAddSibling, handleAddSpouse, handleEdit, handleDelete]);

  useEffect(() => { drawHorizontal(); }, [drawHorizontal]);
  useEffect(() => { drawVertical(); }, [drawVertical]);

  // Zoom controls
  const zoomIn = () => { if (zoomRef.current) d3.select(svgVerticalRef.current).transition().duration(300).call(zoomRef.current.scaleBy, 1.5); };
  const zoomOut = () => { if (zoomRef.current) d3.select(svgVerticalRef.current).transition().duration(300).call(zoomRef.current.scaleBy, 0.7); };
  const zoomReset = () => { if (zoomRef.current) d3.select(svgVerticalRef.current).transition().duration(300).call(zoomRef.current.transform, d3.zoomIdentity); };

  if (loading) return <Typography sx={{ textAlign: 'center', mt: 4 }}>Loading...</Typography>;

  return (
    <div style={{ width: '100%', height: '100%', display: 'flex', flexDirection: 'column', overflow: 'hidden' }}>
      <Typography variant="h5" align="center" sx={{ mt: 2, mb: 1, color: '#2E7D32', fontWeight: 'bold' }}>
        سلسلہ: حضرت آدم (ع) تا حضرت محمد مصطفیٰ ﷺ
      </Typography>

      <div style={{ flex: 1, overflow: 'auto', padding: '10px' }}>
        {/* Horizontal Section */}
        <div style={{ marginBottom: 20 }}>
          <div ref={containerHorizontalRef} style={{ overflow: 'auto' }}>
            <svg ref={svgHorizontalRef} style={{ display: 'block', width: '100%', minHeight: '200px' }} />
          </div>
        </div>

        {/* Vertical Section */}
        <div>
          <div ref={containerVerticalRef} className="tree-bg" style={{ overflow: 'auto', minHeight: '300px' }}>
            <svg ref={svgVerticalRef} style={{ display: 'block', width: '100%', height: '100%' }} />
          </div>
        </div>
      </div>

      <div className="control-bar">
        <button onClick={zoomOut} title="Zoom Out"><ZoomOutIcon fontSize="inherit" /></button>
        <button onClick={zoomReset} title="Reset Zoom"><CenterFocusStrongIcon fontSize="inherit" /></button>
        <button onClick={zoomIn} title="Zoom In"><ZoomInIcon fontSize="inherit" /></button>
        {isAdmin && verticalChain.length > 0 && (
          <button onClick={() => handleAddChild(verticalChain[verticalChain.length - 1])} title="Add Last">+ Add</button>
        )}
      </div>

      {/* Add/Edit Dialogs (same as before) */}
    </div>
  );
}

export default AdamToMuhammad;
